import os
import anthropic
from chaos_client import ChaosClaudeClient

def build_claude_client() -> anthropic.AsyncAnthropic | ChaosClaudeClient:
    real = anthropic.AsyncAnthropic(api_key=os.environ["ANTHROPIC_API_KEY"])
    chaos_profile = os.environ.get("CHAOS_PROFILE", "off")
    if chaos_profile == "timeout":
        return ChaosClaudeClient(real, timeout_rate=0.2, timeout_seconds=35.0)
    if chaos_profile == "rate_limit":
        return ChaosClaudeClient(real, rate_limit_rate=0.3)
    if chaos_profile == "truncate":
        return ChaosClaudeClient(real, truncate_rate=0.15)
    return real

