import time
from enum import Enum
from dataclasses import dataclass, field


class State(Enum):
    CLOSED = "closed"      # normal operation
    OPEN = "open"          # failing fast
    HALF_OPEN = "half_open"  # probing for recovery


@dataclass
class CircuitBreaker:
    failure_threshold: int = 5       # open after N consecutive failures
    recovery_timeout: float = 60.0   # seconds before probe attempt
    _failures: int = field(default=0, init=False)
    _state: State = field(default=State.CLOSED, init=False)
    _opened_at: float = field(default=0.0, init=False)

    def call_allowed(self) -> bool:
        if self._state == State.CLOSED:
            return True
        if self._state == State.OPEN:
            if time.monotonic() - self._opened_at >= self.recovery_timeout:
                self._state = State.HALF_OPEN
                return True  # allow one probe
            return False
        return True  # HALF_OPEN: allow the probe

    def record_success(self) -> None:
        self._failures = 0
        self._state = State.CLOSED

    def record_failure(self) -> None:
        self._failures += 1
        if self._failures >= self.failure_threshold:
            self._state = State.OPEN
            self._opened_at = time.monotonic()

    @property
    def state(self) -> str:
        return self._state.value


_cb = CircuitBreaker()


async def protected_claude_call(prompt: str) -> str:
    if not _cb.call_allowed():
        raise RuntimeError(f"circuit open ({_cb.state}), Claude API calls paused")
    try:
        result = await claude_client.messages_create(
            model="claude-sonnet-5",
            max_tokens=512,
            messages=[{"role": "user", "content": prompt}],
        )
        _cb.record_success()
        return result.content[0].text
    except (anthropic.APITimeoutError, anthropic.APIConnectionError) as exc:
        _cb.record_failure()
        raise

import asyncio
import random
import anthropic


async def call_with_retry(
    client: anthropic.AsyncAnthropic,
    prompt: str,
    max_attempts: int = 3,
) -> str:
    for attempt in range(max_attempts):
        try:
            msg = await client.messages.create(
                model="claude-sonnet-5",
                max_tokens=1024,
                messages=[{"role": "user", "content": prompt}],
            )
            return msg.content[0].text

        except anthropic.RateLimitError as exc:
            retry_after = float(exc.response.headers.get("retry-after", 60))
            if attempt == max_attempts - 1:
                raise
            await asyncio.sleep(retry_after)

        except anthropic.APITimeoutError:
            if attempt == max_attempts - 1:
                raise
            delay = (2 ** attempt) + random.uniform(0, 1)
            await asyncio.sleep(delay)

        except anthropic.InternalServerError:
            if attempt == max_attempts - 1:
                raise
            delay = (2 ** attempt) * 2 + random.uniform(0, 2)
            await asyncio.sleep(delay)

        except anthropic.BadRequestError:
            raise  # never retry 400
    raise RuntimeError("unreachable")
